    ["Stored exclusion for '%s'. Disable to remove from the persistent exclusion set."] = "Exclusión guardada para '%s'. Desactívala para quitarla del conjunto de exclusión persistente.",
    ["Strength"] = "Fuerza",
    ["Stretch bars to match the width of the frame they anchor to (e.g. the player frame)."] = "Estira las barras para que coincidan con el ancho del marco al que se anclan (por ejemplo, el marco del jugador).",
